/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
/// /// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ETG_ItemQualityGrpMaster, ETG_ItemQualityGrp_GroupId), FormControlEventType::Modified)]
public static void ETG_ItemQualityGrp_GroupId_OnModified(FormControl sender, FormControlEventArgs e)
{
    AgreementLine                           agreementLine;
    InventTable                             inventTable;
    ETG_ItemQualitySpecDetails              itemQualitySpecDetails;
    ETG_QualitySubGrpView                   qualitySubGrpView;
    Name        grpId   = sender.valueStr();

    FormDataSource  inventTable_ds   = sender.formRun().dataSource(formDataSourceStr(ETG_ItemQualityGrpMaster, InventTable))  as FormDataSource;
    inventTable                      = inventTable_ds.cursor();

    while select * from qualitySubGrpView
        where qualitySubGrpView.GroupID == grpId
    {
        itemQualitySpecDetails.MinRange                 = qualitySubGrpView.MinRange;
        itemQualitySpecDetails.MaxRange                 = qualitySubGrpView.MaxRange;
        itemQualitySpecDetails.AdjustmentType           = qualitySubGrpView.AdjustmentType;
        itemQualitySpecDetails.Increment                = qualitySubGrpView.Increment;
        itemQualitySpecDetails.FixedValue               = qualitySubGrpView.FixedValue;
        itemQualitySpecDetails.SubGroupId               = qualitySubGrpView.SubGroupID;
        itemQualitySpecDetails.ItemId                   = inventTable.ItemId;
        itemQualitySpecDetails.GroupID                  = qualitySubGrpView.GroupID;
        itemQualitySpecDetails.GroupDescription         = qualitySubGrpView.GroupDescription;
        itemQualitySpecDetails.SubGrpId                 = qualitySubGrpView.SubGroupID;
        itemQualitySpecDetails.SubGroupDescription      = qualitySubGrpView.SubGroupDescription;
        itemQualitySpecDetails.insert();
    }

}
